import type { MapRef } from '@vis.gl/react-maplibre';
import { useMap } from '@vis.gl/react-maplibre';
import { isNil, isString, isUndefined } from 'lodash-es';
import type { MapLayerMouseEvent } from 'maplibre-gl';
import { useCallback, useEffect } from 'react';

import { BASE_LAYER_IDS } from '../constants.js';
import {
  getAssociatedFeatures,
  hasAssociatedFeatures,
  isAssociatedFeature,
} from '../utils/associated-features.js';
import { getMinValueFeature } from '../utils/get-min-value-feature.js';

/**
 * Checks whether a feature exists from a given source
 *
 * @param map -
 * @param source -
 * @param id -
 */
const featureExists = (
  map: MapRef,
  source: string,
  id: string | number,
): boolean => {
  const isSourcePresent = map.getSource(source) !== undefined;

  return (
    isSourcePresent &&
    map.getFeatureState({
      source,
      id,
    }) !== undefined
  );
};

/**
 * Removes hovered state from a feature and its associated features from a given source
 * @param map -
 * @param source -
 * @param id -
 */
const blurFeature = (map: MapRef, source: string, id: string | number) => {
  map.setFeatureState({ source, id }, { hover: false });

  if (isString(id) && hasAssociatedFeatures(id)) {
    for (const associatedFeature of getAssociatedFeatures('connection')) {
      const associatedSource = `${source}-direction`;
      const associatedId = `${id}-${associatedFeature}`;

      if (featureExists(map, associatedSource, associatedId)) {
        map.setFeatureState(
          { source: associatedSource, id: associatedId },
          {
            hover: false,
          },
        );
      }
    }
  }
};

/**
 * Sets hovered state to a feature and its associated features from a given source
 * @param map -
 * @param source -
 * @param id -
 */
const hoverFeature = (map: MapRef, source: string, id: string | number) => {
  map.setFeatureState({ source, id }, { hover: true });

  if (isString(id) && hasAssociatedFeatures(id)) {
    for (const associatedFeature of getAssociatedFeatures('connection')) {
      const associatedSource = `${source}-direction`;
      const associatedId = `${id}-${associatedFeature}`;

      if (featureExists(map, associatedSource, associatedId)) {
        map.setFeatureState(
          { source: `${source}-direction`, id: `${id}-${associatedFeature}` },
          {
            hover: true,
          },
        );
      }
    }
  }
};

/**
 * Sets and removes hovered state to the features depending on mouse position
 */
export const useHoverInteraction = () => {
  const map = useMap().current;

  let featureId: string | number | undefined;
  let sourceId: string | undefined;

  const handleMouseOut = useCallback(
    ({ point }: MapLayerMouseEvent) => {
      if (!isNil(map) && !isUndefined(featureId) && !isUndefined(sourceId)) {
        blurFeature(map, sourceId, featureId);
      }
    },
    [featureId, sourceId, map],
  );

  const handleMouseMove = useCallback(
    ({ point }: MapLayerMouseEvent) => {
      if (!isNil(map)) {
        const features = map
          .queryRenderedFeatures(point)
          .filter((feature) => !isAssociatedFeature(feature.properties.id)); // associated features should only have hover state when the main feature is hovered

        map.getCanvas().style.cursor = 'grab';
        const layerId = features?.[0]?.layer?.id;

        const hasHoveredFeatures =
          !isNil(features) && features.length > 0 && !isUndefined(layerId);
        const isBaseLayer = BASE_LAYER_IDS.includes(layerId);

        if (hasHoveredFeatures && !isBaseLayer) {
          map.getCanvas().style.cursor = 'pointer';
          if (!isUndefined(featureId) && !isUndefined(sourceId)) {
            // if there's already a hovered feature, remove the hover state
            blurFeature(map, sourceId, featureId);
          }

          const minFeature = getMinValueFeature(features);

          featureId = minFeature.id;
          sourceId = minFeature.layer.source;

          // add the hover state to the closest feature
          if (!isUndefined(featureId)) {
            hoverFeature(map, sourceId, featureId);
          }
        } else {
          map.getCanvas().style.cursor = 'grab';

          if (!isUndefined(featureId) && !isUndefined(sourceId)) {
            // remove the active state from the last hovered feature
            blurFeature(map, sourceId, featureId);
          }
        }
      }
    },
    [featureId, sourceId, map],
  );

  useEffect(() => {
    map?.on('mousemove', handleMouseMove);
    map?.on('mouseout', handleMouseOut);
    return () => {
      map?.off('mousemove', handleMouseMove);
      map?.off('mouseout', handleMouseOut);
    };
  }, []);
};
